        if (p.wordSpacing) css += 'word-spacing:' + p.wordSpacing + ';';
        if (p.lineHeight) css += 'line-height:' + p.lineHeight + ';';
        if (!css) return html;
        var style = '<style id="alloflow-text-spacing">body{' + css + '}</style>';
