                const lastBracket = s.lastIndexOf(']');
                if (firstBracket >= 0) s = s.substring(firstBracket);
                if (lastBracket >= 0 && lastBracket > firstBracket) s = s.substring(0, s.lastIndexOf(']') + 1);

