                            var safeTitle = (payload.docTitle || 'worksheet').replace(/[^a-zA-Z0-9_-]/g, '_').slice(0, 40);
                            var dateStr = new Date().toISOString().slice(0, 10);
                            a.href = url2;
                            a.download = safeName + '-' + safeTitle + '-' + dateStr + '.alloflow.html';
